const resp = $.steps.searchGmailInvoices.response || {};
const data = resp.data || resp;
const messages = data.messages || data.items || [];
const maxEmails = $.input.maxEmails || 10;
const limited = messages.slice(0, maxEmails);

const emailIds = limited.map(m => m.id || m.messageId || '');
return { emailIds, totalFound: messages.length, processing: emailIds.length };

const iterations = $.steps.fetchEmailDetails.response.iterations || [];

let allEmails = '';
let successCount = 0;
let failCount = 0;

iterations.forEach((iter, i) => {
  const resp = (iter.getEmail && iter.getEmail.response) ? iter.getEmail.response : null;
  const emailData = resp ? (resp.data || resp) : null;

  if (emailData) {
    successCount++;
    const headers = emailData.payload ? emailData.payload.headers || [] : [];
    const subject = headers.find(h => (h.name || '').toLowerCase() === 'subject');
    const from = headers.find(h => (h.name || '').toLowerCase() === 'from');
    const date = headers.find(h => (h.name || '').toLowerCase() === 'date');
    const snippet = emailData.snippet || '';

    allEmails += '=== EMAIL ' + (i + 1) + ' ===\n';
    allEmails += 'Subject: ' + (subject ? subject.value : 'N/A') + '\n';
    allEmails += 'From: ' + (from ? from.value : 'N/A') + '\n';
    allEmails += 'Date: ' + (date ? date.value : 'N/A') + '\n';
    allEmails += 'Preview: ' + snippet.slice(0, 500) + '\n\n';
  } else {
    failCount++;
  }
});

return { allEmails, successCount, failCount };

const emailData = $.steps.compileEmails.output;

let prompt = 'You are an expert accounts payable specialist. Extract invoice data from these email previews. Be precise with amounts and dates.\n\n';
prompt += 'EMAILS TO PROCESS:\n' + emailData.allEmails + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract: vendor name, invoice number, amount, currency, date, due date\n';
prompt += '- If data is not clearly available, mark as "needs review"\n';
prompt += '- Normalize currency amounts (remove symbols, keep decimals)\n';
prompt += '- Format dates as YYYY-MM-DD\n';
prompt += '- Identify if the email is truly an invoice or just marketing\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "invoices": [\n';
prompt += '    {\n';
prompt += '      "vendor": "Company Name",\n';
prompt += '      "invoiceNumber": "INV-001",\n';
prompt += '      "amount": "100.00",\n';
prompt += '      "currency": "USD",\n';
prompt += '      "date": "2025-01-15",\n';
prompt += '      "dueDate": "2025-02-15",\n';
prompt += '      "status": "confirmed/needs_review",\n';
prompt += '      "confidence": "high/medium/low"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalInvoices": 0,\n';
prompt += '  "totalAmount": "0.00",\n';
prompt += '  "skippedEmails": 0,\n';
prompt += '  "summary": "Brief summary of invoice processing"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { invoices: [], totalInvoices: 0, totalAmount: '0.00', skippedEmails: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const emailStats = $.steps.compileEmails.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Invoice Processing Complete', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Emails Processed:*\n' + emailStats.successCount },
  { type: 'mrkdwn', text: '*Invoices Found:*\n' + (ai.totalInvoices || 0) }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Amount:*\n$' + (ai.totalAmount || '0.00') },
  { type: 'mrkdwn', text: '*Skipped:*\n' + (ai.skippedEmails || 0) + ' emails' }
] });
blocks.push({ type: 'divider' });

if (ai.invoices && ai.invoices.length > 0) {
  ai.invoices.slice(0, 8).forEach((inv, i) => {
    const statusIcon = inv.status === 'confirmed' ? ':white_check_mark:' : ':warning:';
    let text = statusIcon + ' *' + (inv.vendor || 'Unknown') + '* - ' + (inv.invoiceNumber || 'N/A');
    text += '\n  Amount: ' + (inv.currency || 'USD') + ' ' + (inv.amount || '0.00');
    text += '  |  Due: ' + (inv.dueDate || 'N/A');
    text += '  |  Confidence: ' + (inv.confidence || 'N/A');
    blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
  });
}

if (ai.summary) {
  blocks.push({ type: 'divider' });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + ai.summary.slice(0, 500) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Gmail + Claude AI + Google Sheets' }] });

const fallback = 'Invoices: ' + (ai.totalInvoices || 0) + ' found, total $' + (ai.totalAmount || '0.00');
return { blocks, fallback };
